void lightSound() => SystemSound.play(SystemSoundType.click);
const devEmail = 'fastunlocked2017@gmail.com';
void copyDevMessage(BuildContext context, String appName) {
  final msg = 'مرحبًا، لدي ملاحظة حول تطبيق $appName.\nالبريد: $devEmail';
  Clipboard.setData(ClipboardData(text: msg));
  lightSound();
  ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text('تم نسخ رسالة المطور')));
}
TextStyle get titleStyle => const TextStyle(fontSize: 24, fontWeight: FontWeight.w900);

void main()=>runApp(const ExpensesApp());class ExpensesApp extends StatelessWidget{const ExpensesApp({super.key});@override Widget build(BuildContext c)=>MaterialApp(debugShowCheckedModeBanner:false,locale:const Locale('ar'),supportedLocales:const[Locale('ar')],localizationsDelegates:GlobalMaterialLocalizations.delegates,theme:ThemeData(useMaterial3:true),home:const ExpensesHome());}
class ExpensesHome extends StatefulWidget{const ExpensesHome({super.key});@override State<ExpensesHome> createState()=>_ExpensesHomeState();}
class _ExpensesHomeState extends State<ExpensesHome>{final amount=TextEditingController();final title=TextEditingController();String cat='عام';List<Map<String,dynamic>> rows=[];final cats=['عام','طعام','مواصلات','بيت','تعليم','دخل'];@override void initState(){super.initState();load();}Future<void>load()async{final p=await SharedPreferences.getInstance();rows=List<Map<String,dynamic>>.from((jsonDecode(p.getString('rows')??'[]')as List).map((e)=>Map<String,dynamic>.from(e)));setState((){});}Future<void>save()async{final p=await SharedPreferences.getInstance();await p.setString('rows',jsonEncode(rows));}double get income=>rows.where((e)=>e['cat']=='دخل').fold(0.0,(s,e)=>s+(e['amount']as num));double get out=>rows.where((e)=>e['cat']!='دخل').fold(0.0,(s,e)=>s+(e['amount']as num));void add(){final v=double.tryParse(amount.text)??0;if(v<=0)return;rows.insert(0,{'title':title.text.isEmpty?cat:title.text,'cat':cat,'amount':v,'date':DateTime.now().toString().substring(0,10)});title.clear();amount.clear();save();lightSound();setState((){});}@override Widget build(BuildContext context)=>Directionality(textDirection:TextDirection.rtl,child:Scaffold(backgroundColor:const Color(0xffeef7f2),body:SafeArea(child:ListView(padding:const EdgeInsets.all(18),children:[Container(padding:const EdgeInsets.all(22),decoration:BoxDecoration(color:const Color(0xff0f766e),borderRadius:BorderRadius.circular(30)),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[const Text('مصاريفي',style:TextStyle(color:Colors.white,fontSize:30,fontWeight:FontWeight.w900)),Text('الصافي ${(income-out).toStringAsFixed(2)}',style:const TextStyle(color:Colors.white,fontSize:20)),const SizedBox(height:15),LinearProgressIndicator(value:income==0?0:(out/income).clamp(0,1),minHeight:10,borderRadius:BorderRadius.circular(20))])),const SizedBox(height:16),Row(children:[Expanded(child:_box('دخل',income,Colors.green)),const SizedBox(width:10),Expanded(child:_box('مصروف',out,Colors.redAccent))]),const SizedBox(height:12),TextField(controller:title,decoration:_dec('الوصف')),const SizedBox(height:8),TextField(controller:amount,keyboardType:TextInputType.number,decoration:_dec('المبلغ')),const SizedBox(height:8),DropdownButtonFormField<String>(initialValue:cat,items:cats.map((e)=>DropdownMenuItem(value:e,child:Text(e))).toList(),onChanged:(v)=>setState(()=>cat=v??cat),decoration:_dec('التصنيف')),const SizedBox(height:8),FilledButton(onPressed:add,child:const Text('إضافة حركة')),const SizedBox(height:10),...rows.map((e)=>Card(child:ListTile(leading:CircleAvatar(child:Text((e['cat']as String)[0])),title:Text(e['title']),subtitle:Text('${e['cat']} • ${e['date']}'),trailing:Text((e['amount']as num).toStringAsFixed(2)),onLongPress:(){rows.remove(e);save();setState((){});lightSound();}))),ListTile(title:const Text('مراسلة المطور'),subtitle:const Text(devEmail),trailing:const Icon(Icons.copy),onTap:()=>copyDevMessage(context,'مصاريفي'))]))));Widget _box(String t,double v,Color c)=>Container(padding:const EdgeInsets.all(16),decoration:BoxDecoration(color:Colors.white,borderRadius:BorderRadius.circular(22)),child:Column(children:[Text(t),Text(v.toStringAsFixed(2),style:TextStyle(color:c,fontSize:22,fontWeight:FontWeight.w900))]));InputDecoration _dec(String l)=>InputDecoration(labelText:l,filled:true,fillColor:Colors.white,border:OutlineInputBorder(borderRadius:BorderRadius.circular(18),borderSide:BorderSide.none));}
